114	export function getAppModelOptions(
115	  provider: ProviderKind,
116	  customModels: readonly string[],
117	  selectedModel?: string | null,
118	): AppModelOption[] {
119	  const options: AppModelOption[] = getModelOptions(provider).map(({ slug, name }) => ({
120	    slug,
121	    name,
122	    isCustom: false,
123	  }));
124	  const seen = new Set(options.map((option) => option.slug));
125	
126	  for (const slug of normalizeCustomModelSlugs(customModels, provider)) {
127	    if (seen.has(slug)) {
128	      continue;
129	    }
130	
131	    seen.add(slug);
132	    options.push({
133	      slug,
134	      name: slug,
135	      isCustom: true,
136	    });
137	  }
138	
139	  const normalizedSelectedModel = normalizeModelSlug(selectedModel, provider);
140	  if (normalizedSelectedModel && !seen.has(normalizedSelectedModel)) {
141	    options.push({
142	      slug: normalizedSelectedModel,
143	      name: normalizedSelectedModel,
144	      isCustom: true,
145	    });
146	  }
147	
148	  return options;
149	}
