43	};
44	const persistedExpandedProjectCwds = new Set<string>();
45	
46	// ── Persist helpers ──────────────────────────────────────────────────
47	
48	function readPersistedState(): AppState {
49	  if (typeof window === "undefined") return initialState;
50	  try {
51	    const raw = window.localStorage.getItem(PERSISTED_STATE_KEY);
52	    if (!raw) return initialState;
53	    const parsed = JSON.parse(raw) as { expandedProjectCwds?: string[] };
54	    persistedExpandedProjectCwds.clear();
55	    for (const cwd of parsed.expandedProjectCwds ?? []) {
56	      if (typeof cwd === "string" && cwd.length > 0) {
57	        persistedExpandedProjectCwds.add(cwd);
58	      }
59	    }
60	    return { ...initialState };
61	  } catch {
62	    return initialState;
63	  }
64	}
65	
66	function persistState(state: AppState): void {
67	  if (typeof window === "undefined") return;
68	  try {
69	    window.localStorage.setItem(
70	      PERSISTED_STATE_KEY,
71	      JSON.stringify({
72	        expandedProjectCwds: state.projects
73	          .filter((project) => project.expanded)
74	          .map((project) => project.cwd),
75	      }),
76	    );
77	    for (const legacyKey of LEGACY_PERSISTED_STATE_KEYS) {
78	      window.localStorage.removeItem(legacyKey);
79	    }
80	  } catch {
81	    // Ignore quota/storage errors to avoid breaking chat UX.
82	  }
83	}
84	
85	// ── Pure helpers ──────────────────────────────────────────────────────
86	
87	function updateThread(
88	  threads: Thread[],
89	  threadId: ThreadId,
90	  updater: (t: Thread) => Thread,
91	): Thread[] {
92	  let changed = false;
93	  const next = threads.map((t) => {
94	    if (t.id !== threadId) return t;
95	    const updated = updater(t);
96	    if (updated !== t) changed = true;
97	    return updated;
98	  });
99	  return changed ? next : threads;
100	}

1	import { WorkerPoolContextProvider, useWorkerPool } from "@pierre/diffs/react";
2	import DiffsWorker from "@pierre/diffs/worker/worker.js?worker";
3	import { useEffect, useMemo, type ReactNode } from "react";
4	import { useTheme } from "../hooks/useTheme";
5	import { resolveDiffThemeName, type DiffThemeName } from "../lib/diffRendering";
6	
7	function DiffWorkerThemeSync({ themeName }: { themeName: DiffThemeName }) {
8	  const workerPool = useWorkerPool();
9	
10	  useEffect(() => {
11	    if (!workerPool) {
12	      return;
13	    }
14	
15	    const current = workerPool.getDiffRenderOptions();
16	    if (current.theme === themeName) {
17	      return;
18	    }
19	
20	    void workerPool
21	      .setRenderOptions({
22	        ...current,
23	        theme: themeName,
24	      })
25	      .catch(() => undefined);
26	  }, [themeName, workerPool]);
27	
28	  return null;
29	}
30	
31	export function DiffWorkerPoolProvider({ children }: { children?: ReactNode }) {
32	  const { resolvedTheme } = useTheme();
33	  const diffThemeName = resolveDiffThemeName(resolvedTheme);
34	  const workerPoolSize = useMemo(() => {
35	    const cores =
36	      typeof navigator === "undefined" ? 4 : Math.max(1, navigator.hardwareConcurrency || 4);
37	    return Math.max(2, Math.min(6, Math.floor(cores / 2)));
38	  }, []);
39	
40	  return (
41	    <WorkerPoolContextProvider
42	      poolOptions={{
43	        workerFactory: () => new DiffsWorker(),
44	        poolSize: workerPoolSize,
45	        totalASTLRUCacheSize: 240,
46	      }}
47	      highlighterOptions={{
48	        theme: diffThemeName,
49	        tokenizeMaxLineLength: 1_000,
50	      }}
51	    >
52	      <DiffWorkerThemeSync themeName={diffThemeName} />
53	      {children}
54	    </WorkerPoolContextProvider>
55	  );
56	}
