/**
 * Semantic color slots used by the app's CSS custom-property system.
 *
 * Each value is a raw CSS color string (hex, oklch, etc.) that will be applied
 * to `:root` via `style.setProperty`.  Keys intentionally mirror the CSS tokens
 * declared in `apps/web/src/index.css` so that Tailwind utilities (bg-background,
 * text-foreground, …) continue to "just work".
 */
export interface ThemeColors {
  /** Page / app background */
  background: string;
  /** Default text color */
  foreground: string;
  /** Primary accent (buttons, links, rings) */
  accent: string;
  /** Sidebar surface */
  sidebar: string;
  /** Editor / main content surface */
  editor: string;
  /** Terminal surface */
  terminal: string;
  /** Status-bar surface */
  statusBar: string;

  // ---- tokens consumed by existing Tailwind / shadcn utilities ----
  card: string;
  cardForeground: string;
  popover: string;
  popoverForeground: string;
  primary: string;
  primaryForeground: string;
  secondary: string;
  secondaryForeground: string;
  muted: string;
  mutedForeground: string;
  accentForeground: string;
  destructive: string;
  border: string;
  input: string;
  ring: string;
}

