import { describe, expect, it } from "vitest";

import { getTheme, listThemes, type Theme, type ThemeColors } from "./themes.js";

/** Every key in ThemeColors that must be a non-empty string. */
const COLOR_KEYS: readonly (keyof ThemeColors)[] = [
  "background",
  "foreground",
  "accent",
  "sidebar",
  "editor",
  "terminal",
  "statusBar",
  "card",
  "cardForeground",
  "popover",
  "popoverForeground",
  "primary",
  "primaryForeground",
  "secondary",
  "secondaryForeground",
  "muted",
  "mutedForeground",
  "accentForeground",
  "destructive",
  "border",
  "input",
  "ring",
];

describe("themes", () => {
  describe("listThemes", () => {
    it("returns at least 3 built-in themes", () => {
      expect(listThemes().length).toBeGreaterThanOrEqual(3);
    });

    it("includes t3-dark, t3-light, and t3-midnight", () => {
      const ids = listThemes().map((t) => t.id);
      expect(ids).toContain("t3-dark");
      expect(ids).toContain("t3-light");
      expect(ids).toContain("t3-midnight");
    });

    it("every theme has unique id", () => {
      const ids = listThemes().map((t) => t.id);
      expect(new Set(ids).size).toBe(ids.length);
    });
  });

  describe("getTheme", () => {
    it("returns the requested theme by id", () => {
      const theme = getTheme("t3-light");
      expect(theme.id).toBe("t3-light");
    });

    it("falls back to t3-dark for unknown id", () => {
      const theme = getTheme("nonexistent-theme");
      expect(theme.id).toBe("t3-dark");
    });
  });

  describe("theme data integrity", () => {
    for (const theme of listThemes()) {
      describe(theme.id, () => {
        it("has a non-empty name", () => {
          expect(theme.name.length).toBeGreaterThan(0);
        });

        it('appearance is "light" or "dark"', () => {
          expect(["light", "dark"]).toContain(theme.appearance);
        });

        it("has a valid fontFamily", () => {
          expect(theme.fontFamily.length).toBeGreaterThan(0);
        });

        it("has a positive fontSize", () => {
          expect(theme.fontSize).toBeGreaterThan(0);
        });

        for (const key of COLOR_KEYS) {
          it(`colors.${key} is a non-empty string`, () => {
            expect(typeof theme.colors[key]).toBe("string");
            expect((theme.colors[key] as string).length).toBeGreaterThan(0);
          });
        }
      });
    }
  });
});

