import { useCallback, useEffect, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme, type ThemeColors } from "@t3tools/shared/themes";

// ---------------------------------------------------------------------------
// Storage keys
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:named-theme";
const LEGACY_STORAGE_KEY = "t3code:theme";
const FOLLOW_SYSTEM_KEY = "t3code:theme-follow-system";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------------------------------------------------------------------------
// External-store plumbing (module-level singleton)
// ---------------------------------------------------------------------------

type ThemeSnapshot = {
  themeId: string;
  followSystem: boolean;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

// ---------------------------------------------------------------------------
// Persistence helpers
// ---------------------------------------------------------------------------

function getFollowSystem(): boolean {
  const raw = localStorage.getItem(FOLLOW_SYSTEM_KEY);
  if (raw === "true") return true;
  if (raw === "false") return false;
  // If never set, check for legacy key to decide
  return false;
}

function getStoredThemeId(): string {
