import type { Theme } from "@t3tools/shared/themes";

/**
 * Miniature color preview for a theme.
 *
 * Uses inline styles exclusively so the swatch always reflects the *target*
 * theme's palette rather than the currently-applied CSS variables.
 */
export function ThemePreviewSwatch({ theme }: { theme: Theme }) {
  const { colors } = theme;
  return (
    <div
      className="flex h-14 w-full overflow-hidden rounded-md border border-border"
      style={{ background: colors.background }}
      aria-hidden
    >
      {/* Sidebar sliver */}
      <div className="w-4 shrink-0" style={{ background: colors.sidebar }} />

      {/* Main content area */}
      <div className="flex flex-1 flex-col gap-1 p-1.5">
        {/* "Editor" region */}
        <div className="flex-1 rounded-sm" style={{ background: colors.editor }}>
          {/* Fake text lines */}
          <div className="flex flex-col gap-[3px] p-1">
            <div
              className="h-[3px] w-3/4 rounded-full"
              style={{ background: colors.foreground, opacity: 0.35 }}
            />
            <div
              className="h-[3px] w-1/2 rounded-full"
              style={{ background: colors.accent, opacity: 0.55 }}
            />
          </div>
        </div>

        {/* "Status bar" sliver */}
        <div className="h-1.5 w-full rounded-sm" style={{ background: colors.statusBar }} />
      </div>
    </div>
  );
}

